describe('Personal Bests UI — error state', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubPageDeps()

    cy.intercept('GET', PERSONAL_BESTS_EP, {
      statusCode: 500,
      body: {},
    }).as('getPersonalBests')

    visitAndWait()
    cy.wait('@getPersonalBests')
  })

  it('renders #personalBestsError_analyticsPage', () => {
    cy.get(`#${IDS.personal_bests_error}`).scrollIntoView().should('be.visible')
  })

  it('shows an error message in the error container', () => {
    cy.get(`#${IDS.personal_bests_error}`)
      .scrollIntoView()
      .should('contain.text', 'Failed to load personal bests')
  })

  it('does not render #personalBestsTable_analyticsPage in error state', () => {
    cy.get(`#${IDS.personal_bests_table}`).should('not.exist')
  })
})

