    cy.intercept('GET', PERSONAL_BESTS_EP, {
      statusCode: 200,
      body: {
        data: {
          '1 mile': [],
          '5K': [
            {
              rank: 1,
              elapsed_time_sec: 1350,
              pace_sec_per_km: 270,
              date: '2026-01-15T08:00:00Z',
              activity_id: 'activity-abc-123',
              pr_rank: 1,
            },
          ],
          '10K': [],
          '15K': [],
          'Half-Marathon': [],
        },
        message: 'OK',
      },
    }).as('getPersonalBests')

    visitAndWait()
